(499, 'Shadow Walker', 'The Shadow Walker is an old god, worshiped by an unnerving race of humanoids bound to their planet through self destruction. I descended upon their planet during the 1,000 year Festival of Shadows, only to find their motives be sinister in nature. ', 610, 'https://discoveryprovider.audius.co/v1/tracks/EW4Vo/stream'),
(500, 'Deadcrow - Fallout (TRIGO REMIX)', NULL, 611, 'https://discoveryprovider.audius.co/v1/tracks/q5rgb/stream'),
(501, 'S.Maze - Enigma', 'Dont Die At Work Presents the ENIGMA EP by S.Maze. INSERT INTO `songs` (`id`, `name`, `lyrics`, `album_id`, `stream_url`) VALUES
(679, 'Kelbin - Matter', 'After headlining our second KUMO INVITES event, Kelbin debuts on the label with \'Matter\'.\n\n\"I’ve built ‘Matter’ for peak dancefloor moments. I wanted to fuse garage rhythms, intricate synth textures, and vibrant sampling into an energetic yet emotionally resonant track\" - Kelbin \n\nPlay and buy: https://bfan.link/kelbin-matter\n\n-\n\nFollow Kelbin\nhttps://linktr.ee/imkelbin\nhttps://www.instagram.com/imkelbin\nhttps://www.patreon.com/imkelbin\n\nFollow KUMO\nhttps://kumocollective.com\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective', 828, 'https://discoveryprovider.audius.co/v1/tracks/ml3OR1r/stream'),
(680, 'Pluvio & RAZRWAV - Rokstarz', 'UK producers Pluvio and RAZRWAV join forces for their very first collaboration, delivering a face-melting banger that synthesizes together punk, nu-metal and tearout cyberneuro.\n\nListen everywhere: https://bfan.link/rokstarz', 829, 'https://discoveryprovider2.audius.co/v1/tracks/a55A9Wa/stream'),
(681, 'V. Christie - Calling', 'V.Christie debuts on KUMO with a three-minute charmer that warms our hearts with its sun-baked, balearic textures and floating vocal hook. The classic Scandinavian touch for melodies shines above a bouncy bassline and crispy groove.\n\nListen + buy: https://bfan.link/calling-9\n\n-\n\nFollow V.Christie\nhttps://linktr.ee/v.christie\nhttps://www.instagram.com/v.christie_\nhttps://www.tiktok.com/@v.christie_\n\nFollow KUMO\nhttps://kumocollective.com\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective', 830, 'https://discoveryprovider3.audius.co/v1/tracks/QMQwNv/stream'),
(682, 'KUMO INVITES - Kelbin', 'Rising Garage virtuoso Kelbin is debuting in the Netherlands at the upcoming KUMO INVITES show. \n\nBe sure to get your ticket 👉 www.melkweg.nl/nl/agenda/kumo-invites-29-11-2024', 832, 'https://discoveryprovider.audius.co/v1/tracks/bVR4NBJ/stream'),
(683, 'KUMO INVITES - Marlus', 'Our resident dj Marlus is ready to return to Melkweg for the second edition of KUMO INVITES.\n\nTickets 👉 www.melkweg.nl/nl/agenda/kumo-invites-29-11-2024', 833, 'https://discoveryprovider3.audius.co/v1/tracks/YZ8RjgW/stream'),
(684, 'KUMO INVITES - fugue', 'Ahead of his Netherlands debut at the upcoming KUMO INVITES event, fugue has put together an exclusive minimix to give us a taste of his music selection.\n\n Tickets 👉 www.melkweg.nl/nl/agenda/kumo-invites-29-11-2024', 835, 'https://discoveryprovider3.audius.co/v1/tracks/gzjzzvl/stream'),
(685, 'KUMO INVITES - Masha Wordpress ', 'KUMO INVITES // 20.01.2024\n\nBeing born in small cities in Nord Italy where electronic music didn\'t have any space, we quickly fell in love with the multifaceted soul of Amsterdam. Since Patrick moved there, we\'ve always wanted to explore and connect with the local scene and we\'re ecstatic to finally make our first step in this direction.\n\nTo ignite our very first label event at Melkweg, we invited a fresh talent straight from Amsterdam\'s underground scene: Masha Wordpress.\n\nGrab your ticket 🎫: https://www.melkweg.nl/en/agenda/kumo-20-01-2024', 834, 'https://discoveryprovider.audius.co/v1/tracks/dyOP3Pm/stream'),
(686, 'KUMO INVITES: Marlus', 'KUMO INVITES // 20.01.2024\n\nFilippo aka Marlus has been with the team since day 0, so it\'s just natural to have him playing our debut label event. He\'ll join the whole KUMO family in Amsterdam on the 20th of January.\n\nGrab your ticket 🎫: https://www.melkweg.nl/en/agenda/kumo-20-01-2024', 836, 'https://discoveryprovider2.audius.co/v1/tracks/Jgx3Pd6/stream'),
(687, 'KUMO INVITES: Alkyn', 'KUMO INVITES // 20.01.2024\n\nAfter dropping so many gems on the label, Alkyn joins the lineup of our debut club event at the legendary Melkweg, in the heart of Amsterdam 🇳🇱☁️\n\nGrab your ticket 🎫: https://www.melkweg.nl/en/agenda/kumo-20-01-2024\n', 837, 'https://discoveryprovider3.audius.co/v1/tracks/mkNb4q2/stream'),
(688, 'KUMO INVITES: camoufly', 'KUMO INVITES // 20.01.2024\n\ncamoufly is headlining our debut club event at the legendary Melkweg, in the heart of Amsterdam 🇳🇱☁️ \nWe couldn\'t be happier to welcome such a talented artist✨\n\nGrab your ticket 🎫: www.melkweg.nl/nl/agenda/kumo-20-01-2024', 838, 'https://discoveryprovider3.audius.co/v1/tracks/a1OA2r/stream'),
(689, 'Gudboy & TYSHii - Caught Up', 'After the success of our first collaboration, Gudboy is back on KUMO, alongside close friend TYSHii. \n\nCaught Up is a summerish tune that combines the happy hardcore vibes of the vocals with the sparky breakbeat groove flirts with many made-in-UK sounds such as and UKG. A fresh, contemporary take on bass music.\n\n\nArtwork by 6amsunset\n\n\nFollow Gudboy\nhttps://www.instagram.com/whoisgudboy\nhttps://www.tiktok.com/@whoisgudboy\nhttps://twitter.com/whoisgudboy\n\n\nFollow TYSHii\nhttps://tyshiimusic.com\nhttps://www.twitter.com/itstyshii\nhttps://www.instagram.com/itstyshii\nhttps://www.tiktok.com/@itstyshii\n\n\nFollow KUMO\nhttps://kumocollective.com\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\nhttps://twitter.com/KUMOCollective\n', 840, 'https://discoveryprovider.audius.co/v1/tracks/bd8gx7b/stream'),
(690, 'Yash Bansal - Here\'s Hoping', 'Yash Bansal presents: Hell With Love EP\n\n\'Here\'s Hoping\' talks about resilience and self-reflection, about the sense of finding solace in the midst of adversity. Covid is now a topic completely gone from everyday discussions but its effects are still permanent in many’s memory. This delves into his emotional journey during the pandemic, expressing feelings of being lost, stuck, and grappling with romantic disappointment. \n\n\nFollow Yash Bansal\nhttps://linktr.ee/yashbansalmusic\nhttps://www.instagram.com/yashbansalmusic\nhttps://twitter.com/yashbansalmusic\n\n\nFollow KUMO\nhttps://kumocollective.com\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective', 841, 'https://discoveryprovider3.audius.co/v1/tracks/maR52r/stream'),
(691, 'Yash Bansal - Hypoxia', 'Yash Bansal presents: Hell With Love EP\n\nI started this track as an entry for Baauer’s “Bop Battle” beat challenge, where I came up with the main drop idea. For a while, I didn’t think much of the project but over time I found myself constantly coming back to it. The track had this element of catharsis and I felt it would make for a great attention grabbing opener for my EP. I’m particularly proud of the lyrics in this song because typically you wouldn’t find a track like this to tell such an intense story. This proved to be very challenging at first, but I think the results speak for themselves.\n\n\nFollow Yash Bansal\nhttps://linktr.ee/yashbansalmusic\nhttps://www.instagram.com/yashbansalmusic\nhttps://twitter.com/yashbansalmusic\n\n\nFollow KUMO\nhttps://kumocollective.com\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective', 842, 'https://discoveryprovider.audius.co/v1/tracks/o6O58PX/stream'),
(692, 'Yash Bansal - Hell With Love', 'Yash Bansal presents: Hell With Love EP\n\nThis track in a way has been my symbolic rock over the past year. I came up with the main hook melody, probably when I had felt the most broken and lost in my life and yet there was this sense of hope lingering somewhere. Creating the rest of the track was me finding that hope and now, finally being able to put it out to the world, I feel like I can finally let go.\n\n\n\nFollow Yash Bansal\nhttps://linktr.ee/yashbansalmusic\nhttps://www.instagram.com/yashbansalmusic\nhttps://twitter.com/yashbansalmusic\n\nFollow KUMO\nhttps://kumocollective.com\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective', 843, 'https://discoveryprovider2.audius.co/v1/tracks/Zaj9Gyy/stream'),
(693, 'Yash Bansal - Hide The Pain', 'Yash Bansal presents: Hell With Love EP\n\n\'Hide The Pain\'is a journey through the struggles of dealing with the pain we keep pent up inside. The heartfelt vocals focus on genuine emotions, acting as an invitation to put those difficult emotions aside and find solace.\n\n\nFollow Yash Bansal\nhttps://linktr.ee/yashbansalmusic\nhttps://www.instagram.com/yashbansalmusic\nhttps://twitter.com/yashbansalmusic\n\n\nFollow KUMO\nhttps://kumocollective.com\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\n\n', 844, 'https://discoveryprovider.audius.co/v1/tracks/YaYNW6y/stream'),
(694, 'Pala Chrome - You (Harricane Remix)', 'YOU STAY HIGH remix pack - part 3\n\nHarricane turns Pala Chrome\'s YOU into a 4/4 banger.\n\n\n\nFollow Harricane\nhttps://songwhip.com/harricane\nhttps://www.instagram.com/harricane_official\n\n\nFollow Pala Chrome\nhttps://www.instagram.com/palachrome.mp3\nhttps://twitter.com/pala_chrome\n\n\nFollow KUMO\nhttps://kumocollective.com\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective', 845, 'https://discoveryprovider.audius.co/v1/tracks/JagMK2Y/stream'),
(695, 'Pala Chrome - You (Raptures & Crustacean Remix)', 'YOU STAY HIGH remix pack - part 3\n\nFrom India with love, Raptures & Crustacean remix Pala Chrome\'s YOU.\n\n\n\nFollow Raptures\nhttps://www.instagram.com/rapturesmusic\nhttps://www.patreon.com/Raptures\n\n\nFollow Crustacean\nhttps://linktr.ee/ccfeelsaboutyou\nhttps://twitter.com/ccfeelsaboutyou\nhttps://www.instagram.com/ccfeelsaboutyou\n\n\nFollow Pala Chrome\nhttps://www.instagram.com/palachrome.mp3\nhttps://twitter.com/pala_chrome\n\n\nFollow KUMO\nhttps://kumocollective.com\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\n', 846, 'https://discoveryprovider3.audius.co/v1/tracks/ZEv9AvE/stream'),
(696, 'Pala Chrome - You (Jason Baudinet Remix)', 'YOU STAY HIGH remix pack - part 3\n\nSouth Africa\'s own Jason Baudinet remixes Pala Chrome\'s YOU\n\n\n\nFollow Jason Baudinet\nhttps://ffm.bio/jasonbaudinet\nhttps://twitter.com/JasonBaudinet\n\n\nFollow Pala Chrome\nhttps://www.instagram.com/palachrome.mp3\nhttps://twitter.com/pala_chrome\n\n\nFollow KUMO\nhttps://kumocollective.com\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\n', 847, 'https://discoveryprovider3.audius.co/v1/tracks/KxgdBZr/stream'),
(697, 'Pala Chrome - You (imissyou Remix)', 'YOU STAY HIGH remix pack - part 3\n\nimissyou remixes Pala Chrome\'s YOU\n\n\n\nFollow imissyou\nhttps://www.instagram.com/prodbyjosh\n\n\nFollow Pala Chrome\nhttps://www.instagram.com/palachrome.mp3\nhttps://twitter.com/pala_chrome\n\n\nFollow KUMO\nhttps://kumocollective.com\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\n', 848, 'https://discoveryprovider.audius.co/v1/tracks/ZpXZx0a/stream'),
(698, 'Pala Chrome ft. Jeffreymmviii - Stay (Sam Day remix)', 'YOU STAY HIGH remix pack - part 3\n\n\nLondon\'s finest Sam Day leads the third and last part of this monumental remix pack with his tasty UKG take of \'Stay\'.\n\n\nFollow Sam Day\nhttps://www.samday.uk\nhttps://twitter.com/samdayuk\nhttps://www.instagram.com/samdayuk\n\n\nFollow Pala Chrome\nhttps://www.instagram.com/palachrome.mp3\nhttps://twitter.com/pala_chrome\n\n\nFollow KUMO\nhttps://kumocollective.com\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\n', 849, 'https://discoveryprovider.audius.co/v1/tracks/rE96d1O/stream'),
(699, 'Pala Chrome & Dabow ft imissyou - So High (So Sus Remix)', 'YOU STAY HIGH remix pack - part 2\n\nWith their remix of \'So High\', So Sus brings for the very first time the electrifying soundscapes of hardwave on KUMO. \n\n\nFollow So Sus\nhttps://linktr.ee/sosusmusic\nhttps://twitter.com/SoSusMusic\nhttps://www.instagram.com/sosusmusic\n\n\nFollow Pala Chrome\nhttps://www.instagram.com/palachrome.mp3\nhttps://twitter.com/pala_chrome\n\n\nFollow KUMO\nhttps://kumocollective.com\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\n', 851, 'https://discoveryprovider.audius.co/v1/tracks/BNKmNkx/stream'),
(700, 'Pala Chrome ft. Jeffreymmviii - Stay (Dj Premium Timeflex remix)', 'YOU STAY HIGH remix pack - PART 2\n\n\nDJ Premium Timeflex delivers another banging remix, flipping \'Stay\' with his unmistakable funky sound.\n\n\nFollow DJ Premium Timeflex \nhttps://twitter.com/premiumtimeflex\nhttps://www.instagram.com/dj_premiumtimeflex\n\n\nFollow Pala Chrome\nhttps://www.instagram.com/palachrome.mp3\nhttps://twitter.com/pala_chrome\n\n\nFollow KUMO\nhttps://kumocollective.com\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective', 852, 'https://discoveryprovider.audius.co/v1/tracks/blr85RK/stream'),
(701, 'Pala Chrome - You (2chill Remix)', 'The first installment of Pala Chrome\'s \'You Stay High\' remix EP is out, featuring:\n\n2chills\nGabriel Earwood\nalex martian\nDust Of Apollon\nfreeloadr\n\n\nArtworks by 6amsunset.', 854, 'https://discoveryprovider2.audius.co/v1/tracks/Q7VQdJ1/stream'),
(702, 'Pala Chrome - You (freeloadr Remix)', 'The first installment of Pala Chrome\'s \'You Stay High\' remix EP is out, featuring:\n\nfreeloadr\n2chills\nGabriel Earwood\nalex martian\nDust Of Apollon\n\n\nArtworks by 6amsunset.', 855, 'https://discoveryprovider3.audius.co/v1/tracks/WEKKgqv/stream'),
(703, 'Pala Chrome & Dabow ft imissyou - So High (Dust of Apollon Remix)', 'The first installment of Pala Chrome\'s \'You Stay High\' remix EP is out, featuring:\n\nDust Of Apollon\nfreeloadr\n2chills\nGabriel Earwood\nalex martian\n\n\nArtworks by 6amsunset.', 856, 'https://discoveryprovider2.audius.co/v1/tracks/bbA7VRK/stream'),
(704, 'Pala Chrome - You (Gabriel Earwood Remix)', 'The first installment of Pala Chrome\'s \'You Stay High\' remix EP is out, featuring:\n\nGabriel Earwood\nalex martian\nDust Of Apollon\nfreeloadr\n2chills\n\n\nArtworks by 6amsunset.', 857, 'https://discoveryprovider2.audius.co/v1/tracks/kKN8wbp/stream'),
(705, 'La Llave De Tu Corazon', NULL, 924, 'https://discoveryprovider.audius.co/v1/tracks/705G9/stream'),
(706, 'A!RO - Intro', 'PERLIN NOISE EP - OUT NOW\n\nThe journey toward A!RO\'s debut EP has finally come to an end! You can now listen to the full project here on Audius. \n\nTRACKLIST:\nA!RO - Intro\nA!RO ft. Pala Chrome - Butterflies\nA!RO - Skipping Stones\nA!RO- Slate\n\n\nArtwork by 6amsunset\n\n\nFollow A!RO\nhttps://www.instagram.com/snairo_\n\nFollow Pala Chrome\nhttps://www.instagram.com/palachrome.mp3\nhttps://twitter.com/pala_chrome\n\nFollow KUMO\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\nhttps://kumocollective.com', 861, 'https://discoveryprovider2.audius.co/v1/tracks/dYxX0oy/stream'),
(707, 'ell!psis - Chameleon', '\"I came up with the name ‘Chameleon’ because of how many different adaptations I was able to implement with each sound in this track coming together. If you looked at the tools and samples I used in the Ableton file, it probably wouldn\'t make much sense, but I\'m thrilled with how much I was able to blend pretty unorthodox ideas together into something cohesive and catchy.\" \n- ell!psis\n\n\nArtwork by 6amsunset\n\n\nFollow ell!psis\nhttps://www.instagram.com/ell1psis_\nhttps://twitter.com/ell1psis_\n\n\nFollow KUMO\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\nhttps://kumocollective.com\n\n\n\n', 862, 'https://discoveryprovider.audius.co/v1/tracks/BJmMRlY/stream'),
(708, 'blush - The Former', 'It’s with great pleasure that we welcome back blush on KUMO. \n\nHis new creative effort, titled \'The Former\' is a \"tale to make you shiver with joy while giving goosebumps to your arms from a colorful soft atmosphere\" (FUXWITHIT). Read the full article here https://fuxwithit.com/2023/03/31/blush-the-former/\n\n\nArtwork by 6amsunset\n\n\nFollow blush\nhttps://www.instagram.com/blushmusicus/\nhttps://twitter.com/blushmusicus/\n\n\nFollow KUMO\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\nhttps://kumocollective.com', 863, 'https://discoveryprovider3.audius.co/v1/tracks/oRJEJVm/stream'),
(709, 'A!RO - Slate', 'The journey toward A!RO\'s debut EP continues! \'Slate\' is the second (and last) single before the release of the complete project, set for mid-April. \n\nArtwork by 6amsunset\n\n\nFollow A!RO\nhttps://www.instagram.com/snairo_\n\n\nFollow KUMO\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\nhttps://kumocollective.com', 864, 'https://discoveryprovider2.audius.co/v1/tracks/gWr4r5q/stream'),
(710, 'Dabow & CARLIE - 2MINUTES [FUXWITHIT Premiere]', '\"When you see Dabow on KUMO Collective, you know you’re in for a treat\" - FUXWITHIT\n\nFirst aired two weeks ago on BBC Introducing, 2MINUTES is finally out. CARLIE and Dabow have combined their own talents on this springtime housey bop.\n\nRead the blog premiere written by Colin: https://fuxwithit.com/2023/03/09/premiere-dabow-carlie-unite-for-house-leaning-bop-2minutes\n\n\nArtwork by 6amsunset\n\n\nDabow\nhttps://www.instagram.com/dabowmusic\nhttps://twitter.com/dabowmusic\nhttps://linktr.ee/dabowmusic\n\nFollow CARLIE\nhttps://www.instagram.com/itscarliemusic\nhttps://twitter.com/itscarliemusic\nhttps://linktr.ee/itscarliemusic\n\nFollow KUMO\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\nhttps://kumocollective.com\n', 865, 'https://discoveryprovider3.audius.co/v1/tracks/qJxWQqm/stream'),
(711, 'Pala Chrome - Stay (ft. Jeffreymmviii)', 'YOU - STAY - HIGH\n\nThe time has come for Pala Chrome\'s debut EP! Three songs showcasing the immense talent of this amazing artist and friend. STAY is the second cut off the EP and features the vocal of US singer Jeffreymmviii.\n\nArtwork by 6amsunset\n\nFollow Pala Chrome\nhttps://www.instagram.com/palachrome.mp3\nhttps://twitter.com/pala_chrome\n\nFollow Jeffreymmviii\nhttps://www.jeffreymmviii.com\nhttps://www.instagram.com/jeffrey.mmviii\n\nFollow KUMO\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\nhttps://kumocollective.com', 867, 'https://discoveryprovider.audius.co/v1/tracks/wkdVYg1/stream'),
(712, 'A!RO - Butterflies (ft. Pala Chrome)', 'The journey toward A!RO\'s debut EP starts today! We\'re excited to finally share with you \'Butterflies\', the first single from the project. This time the Malaysian producer (also known as S N U G) is joined by our close friend Pala Chrome on vocals.\n\nArtwork by 6amsunset\n\nFollow A!RO\nhttps://www.instagram.com/snairo_\n\nFollow Pala Chrome\nhttps://www.instagram.com/palachrome.mp3\nhttps://twitter.com/pala_chrome\n\nFollow KUMO\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\nhttps://kumocollective.com', 868, 'https://discoveryprovider2.audius.co/v1/tracks/o4pm7xg/stream'),
(713, 'summet - more than anything', 'summet is back ☁️\n\nThe Californian producer is back with his unmistakable sound. \'more than anything\' is the follow-up of his debut album released on KUMO in 2022. Quoting the words of summet himself \"the song talks about silence and silence is the best background to enjoy it“\n\n\nFollow summet\nhttps://www.instagram.com/summetmusic/\nhttps://twitter.com/summetmusic\n\nFollow KUMO\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\nhttps://kumocollective.com', 869, 'https://discoveryprovider.audius.co/v1/tracks/J70PlJ7/stream'),
(714, 'Pala Chrome - You', 'Contest runs March 8th thru March 21st @ 11:59 pm pst\n\nKey: C#minor minus 50 cents (-50 cents)\nBPM: 105bpm\n\nPrizes:\n🥇 1st place: $350 + KUMO Bomber + KUMO stickers\n🥈 2nd place: $100 + KUMO Beanie + KUMO stickers\n🥉 3rd place: $50 + KUMO Stickers\n\nTo enter the contest: simply upload your track to Audius & Tag it as a remix to this track!\n\nWinners will be chosen LIVE on the Audius Discord on the 24th @ 10 am pst\n\nJoin the Audius Discord: discord.gg/audius\n\nJoin KUMO Discord: https://discord.gg/NtPnbBArTk', 870, 'https://discoveryprovider.audius.co/v1/tracks/WNYwG6Z/stream'),
(715, 'Alkyn - Serbia Bass (Blooom \'D&B\' remix)', 'With the beginning of KUMO\'s 6th season just around the corner (January 12), we want to keep the energy high by sharing one of our 2022\'s most heavy and iconic releases, but with a brand-new spin. \n\nFollow Alkyn\nhttps://www.instagram.com/alkynmusic\n\nFollow Blooom\nhttps://twitter.com/BlooomMusic\nhttps://www.instagram.com/blooommusic/\n\nFollow KUMO\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\nhttps://kumocollective.com', 871, 'https://discoveryprovider.audius.co/v1/tracks/Wx4AzG6/stream'),
(716, 'Ignavia - Love Me [from OFFUSCATO 002]', 'OFFUSCATO week, chapter six!\n\nAs the final release of the year, we\'re proud to present you the 2nd installment of our OFFUSCATO compilation series. We\'re almost at the end of our daily uploads journey, after the Christmas break we\'re back with the penultimate single. \n\nRead FUXWITHIT\'s review of the project: https://fuxwithit.com/2022/12/19/kumo-collective-offuscato-vol-002-compilation/\n\nFollow Ignavia\nhttps://www.instagram.com/ignaviaofficial/\nhttps://twitter.com/IgnaviaOfficial\n\nFollow KUMO\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\nhttps://kumocollective.com\n', 873, 'https://discoveryprovider.audius.co/v1/tracks/jlVRdAj/stream'),
(717, 'H4nt - I Really Tried [from OFFUSCATO 002]', 'OFFUSCATO week, chapter five!\n\nAs the final release of the year, we\'re proud to present you the 2nd installment of our OFFUSCATO compilation series. During the course of this week, we\'re uploading one track from the album every day. \n\nRead FUXWITHIT\'s review of the project: https://fuxwithit.com/2022/12/19/kumo-collective-offuscato-vol-002-compilation/\n\nFollow H4nt\nhttps://twitter.com/H4nt_music\nhttps://www.instagram.com/h4nt_music/\nhttps://linktr.ee/h4nt\n\nFollow KUMO\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\nhttps://kumocollective.com\n', 874, 'https://discoveryprovider3.audius.co/v1/tracks/Bxmm2lm/stream'),
(718, 'Joro Dudovski - Cults [from OFFUSCATO 002]', 'OFFUSCATO week, chapter four!\n\nAs the final release of the year, we\'re proud to present you the 2nd installment of our OFFUSCATO compilation series. During the course of this week, we\'re uploading one track from the album every day.\n\nRead FUXWITHIT\'s review of the project: https://fuxwithit.com/2022/12/19/kumo-collective-offuscato-vol-002-compilation/\n\nFollow Joro Dudovski\nhttps://twitter.com/jorodudovski\nhttps://www.instagram.com/jorodudovski\nhttps://www.jorodudovski.com\n\nFollow KUMO\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective\nhttps://www.tiktok.com/@kumocollective\nhttps://kumocollective.com\n', 875, 'https://discoveryprovider2.audius.co/v1/tracks/z8RV1Vz/stream'),
(719, 'Sam Day - Love U, Around Me [from OFFUSCATO 002]', 'OFFUSCATO week, chapter three!\n\nAs the final release of the year, we\'re proud to present you the 2nd installment of our OFFUSCATO compilation series. During the course of this week, we\'re daily uploading a track from the album.\n\nRead FUXWITHIT\'s review of the project: https://fuxwithit.com/2022/12/19/kumo-collective-offuscato-vol-002-compilation/\n\nFollow Sam Day\nhttps://twitter.com/samdayuk\nhttps://www.instagram.com/samdayuk/\n\nFollow KUMO\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective/\nhttps://www.tiktok.com/@kumocollective\nhttps://kumocollective.com\n', 876, 'https://discoveryprovider3.audius.co/v1/tracks/zbO1OXP/stream'),
(720, 'Zimoh - Blinded By Words [from OFFUSCATO 002]', 'OFFUSCATO week, chapter two!\n\nAs the final release of the year, we\'re proud to present the 2nd installment of our OFFUSCATO compilation series. The second track off the album is:\n\nZimoh - Blinded By Words \n\n\nRead FUXWITHIT\'s review of the album: https://fuxwithit.com/2022/12/19/kumo-collective-offuscato-vol-002-compilation/\n\n\nFollow Zimoh:\nhttps://www.instagram.com/zimohh/\nhttps://twitter.com/Zimoh_wav\nhttps://audius.co/zimoh\n\nFollow KUMO\nhttps://twitter.com/KUMOCollective\nhttps://www.instagram.com/kumocollective/\nhttps://www.tiktok.com/@kumocollective\nhttps://kumocollective.com\n\n', 877, 'https://discoveryprovider3.audius.co/v1/tracks/mRrP5W2/stream'),
(721, 'Gudboy - Better [from OFFUSCATO 002]', 'It\'s OFFUSCATO week!\n\nAs the final release of the year, we\'re proud to present the 2nd installment of our OFFUSCATO compilation series. We kick off this week of daily uploads with:\n\nGudboy - Better \n\n\nRead thissongissick\'s review: https://thissongissick.com/post/gudboy-better/\n\n\nFollow Gudboy:\nhttps://www.instagram.com/whoisgudboy/\nhttps://www.tiktok.com/@whoisgudboy\nhttps://twitter.com/whoisgudboy\n\nFollow KUMO\nhttps://www.instagram.com/kumocollective/\nhttps://www.tiktok.com/@kumocollective\nhttps://twitter.com/KUMOCollective\nhttps://kumocollective.com', 878, 'https://discoveryprovider2.audius.co/v1/tracks/Vp76vzb/stream'),
(722, 'Mazare & Heart Of Gold - Drive [Headbang Society Premiere]', 'We are happy to welcome Mazare and Heart of Gold to the KUMO family ☁️ Drum&bass and punk-rock combine in their brand new collaboration titled \'Drive\'.\n\nRead Headbang Society\'s Premiere: https://headbangsociety.com/mazare-x-heart-of-gold-break-it-down-w-new-track-drive/\n\nAvailable on all streaming platforms and digital stores: https://lnk.fu.ga/mazareheartofgold_drive\n\nMazare\nhttps://twitter.com/mazaremusic\nhttps://www.instagram.com/mazaremusic/\nhttps://www.tiktok.com/@mazaremusic\n\nHeart of Gold\nhttps://twitter.com/heartofgold_uk\nhttps://www.instagram.com/thisisheartofgold/\nhttps://www.tiktok.com/@thisisheartofgold', 879, 'https://discoveryprovider3.audius.co/v1/tracks/g4mkoPq/stream'),
(723, 'msft. & VARI - Crash Test [Headbang Society Premiere]', 'Our good friends msft. and VARI bring some serious rave vibes on the label with \'Crash Test\' ☢️ It\'s official. It\'s breakbeat season!\n\nRead Headbang Society\'s Premiere: https://headbangsociety.com/msft-x-vari-bring-the-heat-w-new-track-crash-test-via-kumo/\n\nAvailable on all streaming platforms and digital stores: https://lnk.fu.ga/msftvari_crashtest\n\nmsft.\nhttps://twitter.com/msft_fml\nhttps://www.instagram.com/msftgram/\n\nVARI\nhttps://twitter.com/VARI_MUSIC\nhttps://www.instagram.com/variofficial/', 880, 'https://discoveryprovider.audius.co/v1/tracks/kRKKP/stream'),
