(862, 'Producer-Work Balance', 'In The Loop  Podcast #5: Chris joins Bvckets, a producer who blends styles of Downtempo, Trap, and Experimental Bass, he creates music to transport the listener somewhere else. They discuss balancing a full time job and producing, Bvcket\'s start to music, and what his process is to music production.\n.\n.\n.\n.\n. \nFollow Us! \nhttps:\\/\\/www.instagram.com\\/itl_studios  \nhttps:\\/\\/www.tiktok.com\\/@itl_studios \nhttps:\\/\\/twitter.com\\/itl_studios \n.  \nVisit our Blog! https:\\/\\/blog.intheloopstudio.com \n. \nJoin our Discord!  https:\\/\\/discord.gg\\/y7vzPAXgMh', 1048, 'https://discoveryprovider.audius.co/v1/tracks/RYO4RAw/stream'),
(863, 'Producer-Work Balance', 'In The Loop  Podcast #5: Chris joins Bvckets, a producer who blends styles of Downtempo, Trap, and Experimental Bass, he creates music to transport the listener somewhere else. They discuss balancing a full time job and producing, Bvcket\'s start to music, and what his process is to music production.\n.\n.\n.\n.\n. \nFollow Us! \nhttps:\\/\\/www.instagram.com\\/itl_studios  \nhttps:\\/\\/www.tiktok.com\\/@itl_studios \nhttps:\\/\\/twitter.com\\/itl_studios \n.  \nVisit our Blog! https:\\/\\/blog.intheloopstudio.com \n. \nJoin our Discord!  https:\\/\\/discord.gg\\/y7vzPAXgMh', 1048, 'https://discoveryprovider2.audius.co/v1/tracks/q40Y2lY/stream'),
(864, 'A Passion for Music (feat. Ellisd)', 'In The Loop Podcast #4: Thomas and Chris join David Ellis aka Ellisd to talk about his start to music, his personal process for making music, and artists who follow their passion. \n.\n.\n.\n.\n.\nFollow Us!\nhttps:\\/\\/www.instagram.com\\/itl_studios\nhttps:\\/\\/www.tiktok.com\\/@itl_studios\nhttps:\\/\\/twitter.com\\/itl_studios\n.\nVisit our Blog! https:\\/\\/blog.intheloopstudio.com\n.\nJoin our Discord! https:\\/\\/discord.gg\\/y7vzPAXgMh', 1049, 'https://discoveryprovider2.audius.co/v1/tracks/rzRxM0Z/stream'),
(865, 'Are we running out of music?, Code Beats, Recommending music (feat. Thomas Levine)', 'In The Loop Podcast #1: Chris and John of In The Loop talk to Thomas Levine of Code Beats about Learning Music during the Pandemic, the impact of TikTok on the music industry, and the looming concern of genres running out of chord progressions\n.\n. \n. \n. \n. \nFollow us! \nhttps:\\/\\/www.instagram.com\\/itl_studios\\/ \nhttps:\\/\\/www.tiktok.com\\/@itl_studios?lang=en https:\\/\\/twitter.com\\/itl_studios\n. \nVisit our Blog! https:\\/\\/blog.intheloopstudio.com\\/\n. \nJoin our Discord! https:\\/\\/discord.gg\\/y7vzPAXgMh', 1051, 'https://discoveryprovider2.audius.co/v1/tracks/Aky8lXm/stream'),
